&lt;p&gt;&lt;u&gt;&lt;strong&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;प्रमुख बिंदु&lt;/font&gt;&lt;/font&gt;&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;राष्ट्रीय पंचायती राज दिवस&lt;/font&gt;&lt;/font&gt;&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;पहला&amp;nbsp;&lt;/font&gt;&lt;/font&gt;&lt;strong&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;राष्ट्रीय पंचायती राज दिवस &lt;/font&gt;&lt;/font&gt;&lt;/strong&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;strong&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;2010&lt;/font&gt;&lt;/strong&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt; में मनाया गया था&lt;/font&gt;&lt;/font&gt;।&amp;nbsp;&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;तब से, &lt;/font&gt;&lt;/font&gt;&lt;span style=&quot;color:  (37, 37, 37);  &quot;&gt;भारत में हर साल 24 अप्रैल को राष्ट्रीय पंचायती राज दिवस मनाया जाता है।&lt;/span&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt; &lt;/font&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;अत: विकल्प 1 सही है।&lt;/font&gt;&lt;/font&gt;&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;वार्षिक उत्सव उस दिन को मनाने के लिए किया जाता है जिस दिन &lt;/font&gt;&lt;/font&gt;&lt;strong&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;1992 में 73वां संविधान संशोधन पारित किया गया था।&lt;/font&gt;&lt;/font&gt;&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;यह अधिनियम &lt;/font&gt;&lt;strong&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;24 अप्रैल, 1993&lt;/font&gt;&lt;/strong&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt; को प्रभावी हुआ&lt;/font&gt;&lt;/font&gt;।&lt;/li&gt;
		&lt;li&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;पूर्व प्रधानमंत्री मनमोहन सिंह ने वर्ष 2010 में 24 अप्रैल को पहला राष्ट्रीय पंचायती राज दिवस घोषित किया था।&lt;/font&gt;&lt;/font&gt;&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;राष्ट्रीय पंचायती राज दिवस विकेंद्रीकृत शक्ति की स्थापना को चिह्नित करने के लिए मनाया जाता है।&lt;/font&gt;&lt;/font&gt;&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;color:  (37, 37, 37);  &quot;&gt;पंचायती राज मंत्रालय देश भर में सर्वश्रेष्ठ प्रदर्शन करने वाली पंचायतों/राज्यों/केंद्र शासित प्रदेशों को उनके अच्छे काम के लिए पुरस्कृत करता रहा है।&lt;/span&gt;&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;संविधान के लागू होने के बाद,&amp;nbsp;&lt;/font&gt;&lt;/font&gt;&lt;strong&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;अनुच्छेद 40&lt;/font&gt;&lt;/font&gt;&lt;/strong&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt; में पंचायतों का उल्लेख किया गया, और&amp;nbsp;&lt;/font&gt;&lt;/font&gt;&lt;strong&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;अनुच्छेद 246&lt;/font&gt;&lt;/font&gt;&lt;/strong&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&lt;font style=&quot;vertical-align: inherit;&quot;&gt;&amp;nbsp;ने राज्य विधायिका को स्थानीय स्वशासन से संबंधित किसी भी विषय से संबंधित कानून बनाने का अधिकार दिया।&lt;/font&gt;&lt;/font&gt;&lt;/li&gt;
